namespace BgControls.Windows.Input.Touch;/// <summary>/// 拖拽手势识别器工厂类，用于创建拖拽识别实例./// </summary>public class DragGestureRecognizerFactory : IGestureRecognizerFactory{    /// <summary>    /// Initializes a new instance of the <see cref="DragGestureRecognizerFactory"/> class.    /// </summary>    public DragGestureRecognizerFactory()    {        // 构造函数逻辑.    }    /// <summary>    /// Gets 拖拽手势识别器的优先级.    /// </summary>    public int Priority => TouchManager.DragPriority;    /// <summary>    /// 为指定的 UI 元素创建拖拽手势识别器实例.    /// </summary>    /// <param name="element">关联的 UI 元素.</param>    /// <returns>返回新创建的拖拽手势识别器.</returns>    public GestureRecognizerBase CreateGestureRecognizer(UIElement element)    {        // 检查传入的 UI 元素是否为空.        ArgumentNullException.ThrowIfNull(element, nameof(element));        // 实例化并返回特定于该元素的拖拽手势识别器.        return new DragGestureRecognizer(element);    }    /// <summary>    /// 注册手势之间的状态转换规则.    /// </summary>    public void RegisterGestureTransitions()    {        // 目前拖拽手势没有特殊的转换注册需求.    }}